const input = $input.first().json;

// Handle array response (synchronous success)
if (Array.isArray(input)) {
  if (input.length === 0) {
    return [{ json: { error: 'Bright Data returned empty results', status: 'no_data' } }];
  }
  return input.map(item => ({ json: { ...item, status: 'ok' } }));
}

// Handle object response
if (input.snapshot_id) {
  return [{ json: { error: 'Async response - snapshot not ready', snapshot_id: input.snapshot_id, status: 'async_pending' } }];
}

if (input.error || input.message) {
  return [{ json: { error: input.error || input.message, status: 'api_error' } }];
}

// Pass through valid single-object response
return [{ json: { ...input, status: 'ok' } }];

