const items = $input.all();
return items.map(item => {
  const d = item.json;
  const followers = d.followers_count || d.follower_count || 1;
  const avgLikes = d.avg_likes || d.edge_liked_by || 0;
  const avgComments = d.avg_comments || 0;
  const engagementRate = ((avgLikes + avgComments) / followers * 100).toFixed(2);
  const postsPerWeek = d.media_count ? Math.min(d.media_count / 52, 20).toFixed(1) : 'unknown';
  return { json: { ...d, calculated_engagement_rate: parseFloat(engagementRate),
    posts_per_week: postsPerWeek, metrics_calculated: true } };
});
